import{_ as r,o as t,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"74. Jury Service","description":"","frontmatter":{"title":"74. Jury Service","eba":"Nurses and Midwives 2024-2028","topics":["leave"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/74-jury-service.md","filePath":"ebas/nurses-midwives/leave/74-jury-service.md"}'),s={name:"ebas/nurses-midwives/leave/74-jury-service.md"};function n(i,e,c,u,l,d){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_74-jury-service" tabindex="-1">74. Jury Service <a class="header-anchor" href="#_74-jury-service" aria-label="Permalink to &quot;74. Jury Service&quot;">​</a></h1><p><strong>74.1</strong> An Employee required to attend for jury service will be reimbursed by the Employer an amount equal to the difference between:</p><p><strong>(a)</strong> the amount paid in respect of attendance for jury service; and</p><p><strong>(b)</strong> the amount the Employee could reasonably expect to have received from the Employer as earnings for that period had the Employee not been performing jury service.</p><p><strong>74.2</strong> An Employee will notify the Employer as soon as possible of the date they are required to attend jury service. The Employee will give the Employer proof of attendance at the court, the duration of such attendance and the amount received for jury service.</p><p>Plain language terms: jury duty, court leave.</p>',6)])])}const v=r(s,[["render",n]]);export{m as __pageData,v as default};
